const stdout = String($input.first().json.stdout || '');
const lines = stdout.split('\n').map(l => l.trim()).filter(Boolean);
const entries = [];
for (const line of lines) { try { entries.push(JSON.parse(line)); } catch (e) {} }
const counts = { 'urgent': 0, 'reply-needed': 0, 'ignore': 0 };
for (const e of entries) { const c = e.category || 'reply-needed'; counts[c] = (counts[c] || 0) + 1; }
let text = 'MORNING DIGEST — ' + new Date().toISOString().slice(0, 10) + '\n';
text += 'Processed ' + entries.length + ' emails: ' + (counts['urgent']||0) + ' urgent, ' + (counts['reply-needed']||0) + ' reply-needed, ' + (counts['ignore']||0) + ' ignored\n\n';
if (entries.length === 0) text += 'No new emails processed since the last digest.';
for (const e of entries) {
  text += '[' + String(e.category || '?').toUpperCase() + '] ' + (e.subject || '(no subject)') + ' — ' + (e.summary || '') + '\n';
  if (e.suggested_reply) text += '   > Suggested reply: ' + e.suggested_reply + '\n';
}
if (text.length > 3900) text = text.slice(0, 3900) + '\n...(truncated)';
return [{ json: { digest: text, count: entries.length } }];
